DROP TABLE IF EXISTS `oner_turkiyenin_ithalati`;

CREATE TABLE `oner_turkiyenin_ithalati` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `tarih` DATETIME,
  `urun` VARCHAR(500),
  `ihracatci_ulke` VARCHAR(500),
  `ithalatci_ulke` VARCHAR(500),
  `ithalat_miktar_kg_adet` BIGINT,
  `ithalat_tutari_dolar` BIGINT,
  `birim_fiyat` DOUBLE,
  `sektor_seciniz` VARCHAR(500),
  `yil` BIGINT,
  `10_sutun` TEXT,
  `11_sutun` TEXT,
  `12_sutun` TEXT,
  `13_sutun` TEXT,
  `14_sutun` TEXT,
  `15_sutun` TEXT,
  `16_sutun` TEXT,
  `17_sutun` TEXT,
  `18_sutun` TEXT,
  `19_sutun` TEXT,
  `20_sutun` TEXT,
  `21_sutun` TEXT,
  `22_sutun` TEXT,
  `23_sutun` TEXT,
  `24_sutun` TEXT,
  `25_sutun` TEXT,
  `26_sutun` TEXT,
  `created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

